  ('pukao-e9ff7ca9-moex-00523', 'pukao-e9ff7ca9', 'pukao-e9ff7ca9-moex-110-d1a761c9', 'sub-pukao-e9ff7ca9-02', NULL, 'single_choice', '依國家賠償法之規定，關於國家賠償請求權之行使，下列敘述何者正確？', '["請求權人限於權利受損害之自然人，不包括法人", "因公務員行為所生之國家賠償責任，賠償義務人為從事該行為之公務員", "請求權人如未經協議程序，即向法院提起國家賠償訴訟，該訴訟不合法", "國家賠償之訴訟，除依國家賠償法之規定外，應準用行政訴訟法之規定"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:30+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "403", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "客家事務行政"}'::jsonb, NULL),
  ('pukao-e9ff7ca9-moex-00524', 'pukao-e9ff7ca9', 'pukao-e9ff7ca9-moex-110-d1a761c9', 'sub-pukao-e9ff7ca9-02', NULL, 'single_choice', '甲之三合院古厝，長期出租他人作為廠房使用。嗣主管機關依法將其列為暫定古蹟，但因承租人之營 運可能破壞古蹟，致甲不得繼續出租。甲得基於下列何者，請求主管機關彌補其租金收益損失？', '["公法上不當得利返還請求權", "損失補償請求權", "國家賠償請求權", "公法上無因管理之管理費用請求權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:30+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "403", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "客家事務行政"}'::jsonb, NULL),
